";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1004\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"WordPress 6.4.1: Actualización de mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"https://es-mx.wordpress.org/2023/11/09/wordpress-6-4-1-actualizacion-de-mantenimiento/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:94:\"https://es-mx.wordpress.org/2023/11/09/wordpress-6-4-1-actualizacion-de-mantenimiento/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Nov 2023 14:24:28 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:13:\"Mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"6.4\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://es-mx.wordpress.org/?p=1001\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:380:\"¡WordPress 6.4.1 ya está disponible! Esta versión menor presenta cuatro correcciones de errores. Puedes revisar un resumen de las actualizaciones de mantenimiento en esta versión leyendo el anuncio de la versión candidata o viendo la lista de tickets en Trac. WordPress 6.4.1 es una versión de ciclo corto. Si tienes sitios que admiten actualizaciones automáticas [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Abraham Morales (soyabrahamdev)\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6118:\"\n<h2 class=\"wp-block-heading\">¡WordPress 6.4.1 ya está disponible!</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Esta versión menor presenta <a href=\"https://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=closed&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;id=!59852&amp;milestone=6.4.1&amp;col=id&amp;col=summary&amp;col=status&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=priority\">cuatro correcciones de errores</a>. Puedes revisar un resumen de las actualizaciones de mantenimiento en esta versión leyendo el <a href=\"https://make.wordpress.org/core/2023/11/08/wordpress-6-4-1-rc1-is-now-available/\">anuncio de la versión candidata</a> o <a href=\"https://core.trac.wordpress.org/query?status=accepted&amp;status=assigned&amp;status=closed&amp;status=new&amp;status=reopened&amp;status=reviewing&amp;milestone=6.4.1&amp;col=id&amp;col=summary&amp;col=status&amp;col=owner&amp;col=type&amp;col=priority&amp;col=milestone&amp;order=priority\">viendo la lista de tickets en Trac</a>.</p>\n\n\n\n<span id=\"more-1001\"></span>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.4.1 es una versión de ciclo corto. Si tienes sitios que admiten actualizaciones automáticas en segundo plano, el proceso de actualización comenzará automáticamente. Si tu sitio no se actualiza automáticamente, también puedes actualizarlo desde tu Escritorio de WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Puedes <a href=\"https://es-mx.wordpress.org/wordpress-6.4.1-es_MX.zip\">descargar WordPress 6.4.1 desde WordPress.org</a> o visitar tu Escritorio de WordPress, hacer clic en &#8220;Actualizaciones&#8221; y luego hacer clic en &#8220;Actualizar ahora&#8221;.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Para obtener más información sobre esta versión, <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-4-1/\">visita el sitio HelpHub</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a estos contribuyentes de WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Este lanzamiento fue dirigido por <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a> y <a href=\"https://profiles.wordpress.org/hellofromtonya/\">Tonya Mork</a>. Gracias a todos los que probaron RC y 6.4.1 y generaron informes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.4.1 no habría sido posible sin las contribuciones de las siguientes personas. Su coordinación rápida y concertada para implementar correcciones de mantenimiento en una versión estable es un testimonio del poder y la capacidad de la comunidad de WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://profiles.wordpress.org/afragen/\">@afragen</a> <a href=\"https://profiles.wordpress.org/clorith/\">@clorith</a> <a href=\"https://profiles.wordpress.org/desrosj/\">@desrosj</a> <a href=\"https://profiles.wordpress.org/pbiron/\">@pbiron</a> <a href=\"https://profiles.wordpress.org/schlessera/\">@schlessera</a> <a href=\"https://profiles.wordpress.org/azaozz/\">@azaozz</a> <a href=\"https://profiles.wordpress.org/davidbaumwald/\">@davidbaumwald</a> <a href=\"https://profiles.wordpress.org/tomsommer/\">@tomsommer</a> <a href=\"https://profiles.wordpress.org/nexflaszlo/\">@nexflaszlo</a> <a href=\"https://profiles.wordpress.org/howdy_mcgee/\">@howdy_mcgee</a> <a href=\"https://profiles.wordpress.org/baxbridge/\">@baxbridge</a> <a href=\"https://profiles.wordpress.org/earnjam/\">@earnjam</a> <a href=\"https://profiles.wordpress.org/timothyblynjacobs/\">@timothyblynjacobs</a> <a href=\"https://profiles.wordpress.org/johnbillion/\">@johnbillion</a> <a href=\"https://profiles.wordpress.org/flixos90/\">@flixos90</a> <a href=\"https://profiles.wordpress.org/joedolson/\">@joedolson</a> <a href=\"https://profiles.wordpress.org/jeffpaul/\">@jeffpaul</a> <a href=\"https://profiles.wordpress.org/zunaid321/\">@zunaid321</a> <a href=\"https://profiles.wordpress.org/courane01/\">@courane01</a> <a href=\"https://profiles.wordpress.org/audrasjb/\">@audrasjb</a> <a href=\"https://profiles.wordpress.org/tacoverdo/\">@tacoverdo</a> <a href=\"https://profiles.wordpress.org/ironprogrammer/\">@ironprogrammer</a> <a href=\"https://profiles.wordpress.org/webcommsat/\">@webcommsat</a> <a href=\"https://profiles.wordpress.org/otto42/\">@otto42</a> <a href=\"https://profiles.wordpress.org/barry/\">@barry</a> <a href=\"https://profiles.wordpress.org/chanthaboune/\">@chanthaboune</a> <a href=\"https://profiles.wordpress.org/rajinsharwar/\">@rajinsharwar</a> <a href=\"https://profiles.wordpress.org/aaroncampbell/\">@aaroncampbell</a> <a href=\"https://profiles.wordpress.org/peterwilsoncc/\">@peterwilsoncc</a> <a href=\"https://profiles.wordpress.org/anandau14/\">@anandau14</a> <a href=\"https://profiles.wordpress.org/iandunn/\">@iandunn</a> <a href=\"https://profiles.wordpress.org/matthewjho/\">@matthewjho</a> <a href=\"https://profiles.wordpress.org/coffee2code/\">@coffee2code</a> <a href=\"https://profiles.wordpress.org/boogah/\">@boogah</a> <a href=\"https://profiles.wordpress.org/jason_the_adams/\">@jason_the_adams</a> <a href=\"https://profiles.wordpress.org/joemcgill/\">@joemcgill</a> <a href=\"https://profiles.wordpress.org/johnjamesjacoby/\">@johnjamesjacoby</a> <a href=\"https://profiles.wordpress.org/jrf/\">@jrf</a> <a href=\"https://profiles.wordpress.org/renehermi/\">@renehermi</a> <a href=\"https://profiles.wordpress.org/dlh/\">@dlh</a> <a href=\"https://profiles.wordpress.org/mukesh27/\">@mukesh27</a> <a href=\"https://profiles.wordpress.org/sumitbagthariya16/\">@sumitbagthariya16</a> <a href=\"https://profiles.wordpress.org/starbuck/\">@starbuck</a> <a href=\"https://profiles.wordpress.org/sergeybiryukov/\">@sergeybiryukov</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo contribuir</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Para participar en el desarrollo central de WordPress, diríjete a Trac, <a href=\"https://core.trac.wordpress.org/report/6\">selecciona un ticket</a> y únete a la conversación en el canal <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a>. ¿Necesitas ayuda? Consulta el <a href=\"https://make.wordpress.org/core/handbook/\">Manual del colaborador principal</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://es-mx.wordpress.org/2023/11/09/wordpress-6-4-1-actualizacion-de-mantenimiento/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1001\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:27:\"WordPress 6.4 “Shirley”\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"https://es-mx.wordpress.org/2023/11/09/wordpress-6-4-shirley/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"https://es-mx.wordpress.org/2023/11/09/wordpress-6-4-shirley/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Nov 2023 14:18:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:12:\"Lanzamientos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"6.4\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es-mx.wordpress.org/?p=988\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:334:\"Saluda a WordPress 6.4 “Shirley”, que lleva el nombre de la icónica artista de jazz Shirley Horn. Su voz distintiva y su extraordinaria conexión con el piano la establecieron como una de las principales músicos de jazz de su generación. El viaje de Horn desde la escena del jazz de Washington D.C. hasta el escenario [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Abraham Morales (soyabrahamdev)\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:75814:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://es-mx.wordpress.org/files/2023/11/Release_featured_image2-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://es-mx.wordpress.org/files/2023/11/Release_featured_image2-1-1024x683.png\" alt=\"\" class=\"wp-image-989\" srcset=\"https://es-mx.wordpress.org/files/2023/11/Release_featured_image2-1-1024x683.png 1024w, https://es-mx.wordpress.org/files/2023/11/Release_featured_image2-1-300x200.png 300w, https://es-mx.wordpress.org/files/2023/11/Release_featured_image2-1-768x512.png 768w, https://es-mx.wordpress.org/files/2023/11/Release_featured_image2-1.png 1536w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Saluda a WordPress 6.4 “Shirley”, que lleva el nombre de la icónica artista de jazz <a href=\"https://wikipedia.org/wiki/Shirley_Horn\">Shirley Horn</a>. Su voz distintiva y su extraordinaria conexión con el piano la establecieron como una de las principales músicos de jazz de su generación. El viaje de Horn desde la escena del jazz de Washington D.C. hasta el escenario internacional es un testimonio de su dedicación y perseverancia. Su influencia llegó mucho más allá de los límites del jazz tradicional, rompiendo fronteras e inspirando a audiencias de todo el mundo.</p>\n\n\n\n<span id=\"more-988\"></span>\n\n\n\n<p class=\"wp-block-paragraph\">Disfruta del ritmo suave de la <a href=\"https://www.youtube.com/channel/UCS3pUiY9OmzB6bPta3-4ArQ/playlists\">música de Shirley Horn</a> mientras disfrutas de todo lo que ofrece 6.4.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Esta última versión de WordPress presenta un tema predeterminado nuevo y versátil y un conjunto de actualizaciones para potenciar cada paso de su viaje creativo. Elabora tu contenido sin problemas con más mejoras de redacción. Explora más formas de hacer realidad su visión y optimizar la edición del sitio con herramientas mejoradas. Si eres nuevo en WordPress o un creador experimentado, &#8220;Shirley&#8221; tiene algo para ti. Descubre la flexibilidad inigualable de construir con bloques y deja volar tus ideas.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Muchas de las características y mejoras de WordPress 6.4 se incluyen en la categoría &#8220;pequeñas pero poderosas&#8221;. Junto con la belleza adaptable del tema Twenty Twenty-Four, estas actualizaciones ayudan a los creadores de contenido y desarrolladores de sitios a ahorrar tiempo y esfuerzo al tiempo que brindan la experiencia de WordPress de alto valor y sin complicaciones que el mundo espera.</p>\n<cite>Josepha Haden Chomphosy, directora ejecutiva de WordPress</cite></blockquote>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-36078703 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button is-style-fill\"><a class=\"wp-block-button__link has-white-color has-vivid-cyan-blue-background-color has-text-color has-background has-link-color has-text-align-center wp-element-button\" href=\"https://es-mx.wordpress.org/download/\" style=\"border-radius:0px\" target=\"_blank\" rel=\"noreferrer noopener\">¡Descarga WordPress 6.4 hoy!</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué hay dentro 6.4?</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Conoce Twenty Twenty-Four</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Experimente la edición de sitios en su máxima expresión con <a href=\"https://make.wordpress.org/core/2023/08/24/introducing-twenty-twenty-four/\">Twenty Twenty-Four</a>. Este nuevo tema predeterminado multifacético ha sido cuidadosamente diseñado teniendo en mente tres casos de uso distintos, desde escritores y artistas hasta emprendedores. Ahorra tiempo y esfuerzo con su extensa colección de <a href=\"https://2024.wordpress.net/index.php/patterns/\">más de 35 plantillas y patrones</a> y descubre un mundo de posibilidades creativas con algunos ajustes. La notable flexibilidad de Twenty Twenty-Four garantiza una adaptación ideal para casi cualquier tipo de sitio. <a href=\"https://2024.wordpress.net/\">Compruébalo en esta demostración</a>.</p>\n\n\n\n<figure class=\"wp-block-image size-large is-resized\"><a href=\"https://es-mx.wordpress.org/files/2023/11/tt4.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/tt4-1024x666.png\" alt=\"\" class=\"wp-image-990\" style=\"width:840px;height:auto\" srcset=\"https://es-mx.wordpress.org/files/2023/11/tt4-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/tt4-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/tt4-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/tt4.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Deja que tu escritura fluya</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Las <a href=\"https://make.wordpress.org/core/2023/10/05/core-editor-improvement-ensuring-excellence-in-the-writing-experience/\">nuevas mejoras</a> garantizan que tu proceso de creación de contenido sea fluido. Encuentra nuevos atajos de teclado en la Vista de lista, combinación de listas más inteligente y control mejorado sobre la configuración de enlaces. Una experiencia de barra de herramientas coherente para los bloques de Navegación, Lista y Cotización le permite trabajar de manera eficiente con las opciones de herramientas que necesita.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://es-mx.wordpress.org/files/2023/11/writing.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/writing-1024x666.png\" alt=\"\" class=\"wp-image-991\" srcset=\"https://es-mx.wordpress.org/files/2023/11/writing-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/writing-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/writing-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/writing.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">La paleta de comandos acaba de mejorar</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Introducida por primera vez en WordPress 6.3, la paleta de comandos es una poderosa herramienta para encontrar rápidamente lo que necesitas, realizar tareas de manera eficiente y acelerar el flujo de trabajo de su construcción. Disfruta de<a href=\"https://make.wordpress.org/core/2023/09/12/core-editor-improvement-commanding-the-command-palette/\"> un diseño renovado y nuevos comandos</a> para realizar acciones específicas de bloques en esta versión.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://es-mx.wordpress.org/files/2023/11/commands.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/commands-1024x666.png\" alt=\"\" class=\"wp-image-992\" srcset=\"https://es-mx.wordpress.org/files/2023/11/commands-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/commands-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/commands-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/commands.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Categorizar y filtrar patrones</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Los <a href=\"https://es-mx.wordpress.org/patterns/\">patrones</a> son una excelente manera de aprovechar el potencial de los bloques y simplificar el proceso de creación de tu sitio. WordPress 6.4 te permite organizarlos con categorías personalizadas. Además, el nuevo filtrado avanzado en la sección Patrones del insertador hace que encontrar todos sus patrones sea más intuitivo.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://es-mx.wordpress.org/files/2023/11/categorize-patterns-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/categorize-patterns-1-1024x666.png\" alt=\"\" class=\"wp-image-993\" srcset=\"https://es-mx.wordpress.org/files/2023/11/categorize-patterns-1-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/categorize-patterns-1-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/categorize-patterns-1-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/categorize-patterns-1.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Se creativo con más herramientas de diseño</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Crea diseños atractivos y funcionales con un conjunto ampliado de herramientas de diseño. Juega con imágenes de fondo en bloques de grupo para obtener diseños únicos y mantén las dimensiones de la imagen consistentes con las proporciones de aspecto del marcador de posición. ¿Quieres agregar botones a tu bloque de navegación? Ahora puedes hacerlo cómodamente sin una línea de código.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://es-mx.wordpress.org/files/2023/11/design-tools.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/design-tools-1024x666.png\" alt=\"\" class=\"wp-image-994\" srcset=\"https://es-mx.wordpress.org/files/2023/11/design-tools-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/design-tools-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/design-tools-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/design-tools.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Haz que tus imágenes destaquen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Habilita la funcionalidad de caja de luz para permitir que los visitantes de su sitio disfruten de imágenes interactivas en pantalla completa al hacer clic. Aplícalo globalmente o a imágenes específicas para personalizar la experiencia de visualización.</p>\n\n\n\n<figure class=\"wp-block-image size-large is-resized\"><a href=\"https://es-mx.wordpress.org/files/2023/11/lightbox.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/lightbox-1024x666.png\" alt=\"\" class=\"wp-image-995\" style=\"width:838px;height:auto\" srcset=\"https://es-mx.wordpress.org/files/2023/11/lightbox-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/lightbox-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/lightbox-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/lightbox.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Cambia el nombre de los bloques de grupo</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Pónle un nombre personalizado a los bloques de grupo para organizar y distinguir áreas de su contenido fácilmente. Estos nombres serán visibles en la Vista de lista.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://es-mx.wordpress.org/files/2023/11/rename.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/rename-1024x666.png\" alt=\"\" class=\"wp-image-996\" srcset=\"https://es-mx.wordpress.org/files/2023/11/rename-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/rename-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/rename-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/rename.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Vista previa de imágenes en vista de lista</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Las nuevas vistas previas de los bloques de Galería e Imágenes en la Vista de lista le permiten visualizar y ubicar dónde están las imágenes de tu contenido de un vistazo.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://es-mx.wordpress.org/files/2023/11/list-view-images.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/list-view-images-1024x666.png\" alt=\"\" class=\"wp-image-997\" srcset=\"https://es-mx.wordpress.org/files/2023/11/list-view-images-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/list-view-images-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/list-view-images-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/list-view-images.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Compartir patrones entre sitios</h3>\n\n\n\n<p class=\"wp-block-paragraph\">¿Necesitas utilizar tus patrones personalizados en otro sitio? Importarlos y exportarlos como archivos JSON desde la vista de patrones del Editor del sitio.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://es-mx.wordpress.org/files/2023/11/exporting-patterns-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/exporting-patterns-1-1024x666.png\" alt=\"\" class=\"wp-image-998\" srcset=\"https://es-mx.wordpress.org/files/2023/11/exporting-patterns-1-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/exporting-patterns-1-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/exporting-patterns-1-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/exporting-patterns-1.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Presentación de los bloques Hooks</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Los <a href=\"https://make.wordpress.org/core/2023/10/15/introducing-block-hooks-for-dynamic-blocks/\">bloques Hooks</a> permiten a los desarrolladores insertar automáticamente bloques dinámicos en ubicaciones de contenido específicas, enriqueciendo la extensibilidad de los temas de bloques a través de plugins. Si bien se considera una herramienta para desarrolladores, esta función está diseñada para respetar sus preferencias y le brinda control total para agregar, descartar y personalizar bloques insertados automáticamente según sus necesidades.</p>\n\n\n\n<figure class=\"wp-block-image size-large is-resized\"><a href=\"https://es-mx.wordpress.org/files/2023/11/block-hooks.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"666\" src=\"https://es-mx.wordpress.org/files/2023/11/block-hooks-1024x666.png\" alt=\"\" class=\"wp-image-999\" style=\"width:840px;height:auto\" srcset=\"https://es-mx.wordpress.org/files/2023/11/block-hooks-1024x666.png 1024w, https://es-mx.wordpress.org/files/2023/11/block-hooks-300x195.png 300w, https://es-mx.wordpress.org/files/2023/11/block-hooks-768x499.png 768w, https://es-mx.wordpress.org/files/2023/11/block-hooks.png 1360w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">El rendimiento gana</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Esta versión incluye más de 100 actualizaciones relacionadas con el rendimiento para una experiencia más rápida y eficiente. Las mejoras notables se centran en el rendimiento de <a href=\"https://make.wordpress.org/core/2023/10/17/improvements-to-template-loading-in-wordpress-6-4/\">carga de plantillas para temas</a> (incluido Twenty Twenty-Four), <a href=\"https://make.wordpress.org/core/2023/10/17/script-loading-changes-in-wordpress-6-4/\">el uso de estrategias de carga de scripts</a> &#8220;diferidas&#8221; y &#8220;asíncronas&#8221; en el núcleo, los bloques y los temas, y la <a href=\"https://make.wordpress.org/core/2023/10/17/new-option-functions-in-6-4/\">optimización de las opciones de carga automática</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Aspectos destacados de la accesibilidad</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Cada lanzamiento se compromete a hacer que WordPress sea accesible para todos. WordPress 6.4 trae varias mejoras en la Vista de lista y compatibilidad con etiquetas aria para el bloque de Navegación, entre otras cosas destacadas. La interfaz de usuario del administrador incluye mejoras en la ubicación de los botones, el contexto de los elementos del menú &#8220;Agregar nuevo&#8221; y los mensajes hablados sobre el estado del sitio. Obtén <a href=\"https://make.wordpress.org/core/2023/11/03/wordpress-6-4-accessibility-improvements/\">más información sobre todas las actualizaciones</a> destinadas a mejorar la accesibilidad.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Otras notas de interés</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Se recomienda el uso de PHP 8.1 u 8.2 con WordPress 6.4. Encuentra detalles detallados sobre el soporte de PHP en esta <a href=\"https://wordpress.org/news/2023/10/wordpress-6-4s-php-compatibility/\">entrada (en inglés)</a>.</li>\n\n\n\n<li>WordPress 6.4 <a href=\"https://make.wordpress.org/core/2023/10/16/changes-to-attachment-pages/\">deshabilita las páginas adjuntas</a> para nuevas instalaciones.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Obtén más información sobre WordPress 6.4</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Consulta la nueva <a href=\"https://wordpress.org/download/releases/6-4/\">página de WordPress 6.4</a> para obtener más información sobre las numerosas mejoras y características de esta versión.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Explora <a href=\"https://learn.wordpress.org/\">Learn WordPress</a> para ver videos instructivos rápidos, <a href=\"https://learn.wordpress.org/social-learning/\">talleres en línea</a> y otros recursos gratuitos para mejorar sus conocimientos y habilidades de WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Si buscas notas técnicas detalladas sobre nuevos cambios, la <a href=\"https://make.wordpress.org/core/2023/10/23/wordpress-6-4-field-guide/\">Guía de campo de WordPress 6.4</a> es para ti. No olvides suscribirte al <a href=\"https://developer.wordpress.org/news/\">Blog para desarrolladores</a> para estar al tanto de las últimas actualizaciones de desarrollo, tutoriales y más.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Para obtener más información sobre instalación, correcciones y cambios de archivos, visita las <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-4/\">notas de la versión 6.4</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">El equipo de lanzamiento 6.4</h2>\n\n\n\n<p class=\"wp-block-paragraph\">​​La versión WordPress 6.4 llega de la mano de un <strong>equipo de lanzamiento de género subrepresentado</strong> para dar la bienvenida y potenciar diversas voces en el proyecto de código abierto de WordPress.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Ser parte del equipo de coordinación de la versión 6.4 me ha permitido observar de cerca el intrincado proceso de lanzamiento, donde cada detalle, por menor que sea, se aborda meticulosamente, teniendo en cuenta varios factores como el rendimiento y la compatibilidad con versiones anteriores. Todavía hay mucho que aprender, pero me siento afortunado de haber tenido la oportunidad de contribuir a WordPress 6.4.</p>\n<cite>Akshaya Rane, miembro del equipo coordinador de la versión 6.4</cite></blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">Durante varias semanas, el equipo de lanzamiento 6.4 mantuvo el lanzamiento encaminado y avanzó liderando el trabajo colectivo, conectando ideas y eliminando obstáculos.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Release Lead:&nbsp;<a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha Haden Chomphosy</a></li>\n\n\n\n<li>Release Coordinators:&nbsp;<a href=\"https://profiles.wordpress.org/cbringmann/\">Chloé Bringmann</a>,&nbsp;<a href=\"https://profiles.wordpress.org/metalandcoffee/\">Ebonie Butler</a>,&nbsp;<a href=\"https://profiles.wordpress.org/akshayar/\">Akshaya Rane</a>,&nbsp;<a href=\"https://profiles.wordpress.org/francina/\">Francesca Marano</a>. Cohort:&nbsp;<a href=\"https://profiles.wordpress.org/thewebprincess/\">Dee Teal</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jaimieolmstead/\">Jaimie Olmstead</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jyolsna/\">Jyolsna J E</a>,&nbsp;<a href=\"https://profiles.wordpress.org/marybaum/\">Mary Baum</a></li>\n\n\n\n<li>Core Tech Leads: <a href=\"https://profiles.wordpress.org/mikeschroder/\">Mike Schroder</a>, <a href=\"https://profiles.wordpress.org/hellofromtonya/\">Tonya Mork</a>. Grupo: <a href=\"https://profiles.wordpress.org/pypwalters/\">Stephanie Walters</a></li>\n\n\n\n<li>Editor Tech Leads:  <a href=\"https://profiles.wordpress.org/mikachan/\">Sarah Norris</a>, <a href=\"https://profiles.wordpress.org/siobhyb/\">Siobhan Bamber</a>, <a href=\"https://profiles.wordpress.org/karmatosed/\">Tammie Lister</a>. Grupo: <a href=\"https://profiles.wordpress.org/68kheart/\">Devan Ferguson</a>, <a href=\"https://profiles.wordpress.org/battelfred/\">Frédérique Battel</a>, <a href=\"https://profiles.wordpress.org/jessicagoddard/\">Jessica Goddard</a>, <a href=\"https://profiles.wordpress.org/1happyplace/\">Katie Ayres</a>, <a href=\"https://profiles.wordpress.org/martatorre/\">Marta Torre</a>, <a href=\"https://profiles.wordpress.org/ngreennc/\">Nyasha Green</a>, <a href=\"https://profiles.wordpress.org/poojabhimani/\">Pooja Bhimani</a></li>\n\n\n\n<li>Core Triage Leads:&nbsp;<a href=\"https://profiles.wordpress.org/nicolefurlan/\">Nicole Furlan</a>,&nbsp;<a href=\"https://profiles.wordpress.org/oglekler/\">Olga Gleckler</a></li>\n\n\n\n<li>Editor Triage Leads: <a href=\"https://profiles.wordpress.org/annezazu/\">Anne McCarthy</a>, <a href=\"https://profiles.wordpress.org/bph/\">Birgit Pauli-Haack</a>. Grupo: <a href=\"https://profiles.wordpress.org/emilyatmobtown/\">Emily Leffler Schulman</a></li>\n\n\n\n<li>Documentation Leads: <a href=\"https://profiles.wordpress.org/webcommsat/\">Abha Thakor</a>, <a href=\"https://profiles.wordpress.org/femkreations/\">Femy Praseeth</a>, <a href=\"https://profiles.wordpress.org/611shabnam/\">Mushrit Shabnam</a>. Grupo: <a href=\"https://profiles.wordpress.org/itsjustdj/\">D.J. Billings</a>, <a href=\"https://wordpress.org/support/users/codente/\">Jamie VanRaalte</a>, <a href=\"https://profiles.wordpress.org/newyorkerlaura/\">Laura Byrne</a>, <a href=\"https://profiles.wordpress.org/baxbridge/\">Tiffany Bridge</a>, <a href=\"https://profiles.wordpress.org/planningwrite/\">Winstina Hughes</a></li>\n\n\n\n<li>Marketing and Communications Leads: <a href=\"https://profiles.wordpress.org/meher/\">Meher Bala</a>, <a href=\"https://profiles.wordpress.org/rmartinezduque/\">Reyes Martínez</a>, <a href=\"https://profiles.wordpress.org/sereedmedia/\">Sé Reed</a>. Grupo: <a href=\"https://profiles.wordpress.org/meaganhanes/\">Meagan Hanes</a>, <a href=\"https://profiles.wordpress.org/michelleames/\">Michelle Frechette</a></li>\n\n\n\n<li>Test Lead: <a href=\"https://profiles.wordpress.org/webtechpooja/\">Pooja Derashri</a>. Grupo: <a href=\"https://profiles.wordpress.org/annebovelett/\">Anne Bovelett</a>, <a href=\"https://profiles.wordpress.org/coachbirgit/\">Birgit Olzem</a></li>\n\n\n\n<li>Design Leads: <a href=\"https://profiles.wordpress.org/elmastudio/\">Ellen Bauer</a>, <a href=\"https://profiles.wordpress.org/estelaris/\">Estela Rueda</a>. Grupo: <a href=\"https://profiles.wordpress.org/allisonplus/\">Allison Tarr</a>, <a href=\"https://profiles.wordpress.org/acirujano/\">Ana Cirujano</a>, <a href=\"https://profiles.wordpress.org/cathibosco1/\">Cathi Bosco</a>, <a href=\"https://profiles.wordpress.org/nudge/\">Sonia Gaballa</a>, <a href=\"https://profiles.wordpress.org/ohia/\">Ohia</a></li>\n\n\n\n<li>Performance Lead: <a href=\"https://profiles.wordpress.org/clarkeemily/\">Emily Clarke</a>. Grupo: <a href=\"https://profiles.wordpress.org/linsoftware/\">Linnea Huxford</a></li>\n\n\n\n<li>Training Leads:&nbsp;<a href=\"https://profiles.wordpress.org/courtneypk/\">Courtney P.K.</a>,&nbsp;<a href=\"https://profiles.wordpress.org/courane01/\">Courtney Roberston</a></li>\n\n\n\n<li>Default Theme Leads: <a href=\"https://profiles.wordpress.org/luminuu/\">Jessica Lyschik</a>, <a href=\"https://profiles.wordpress.org/onemaggie/\">Maggie Cabrera</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias contribuyentes.</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress cree en democratizar la publicación y las libertades que conlleva el código abierto. Apoyando esta idea hay una comunidad global y diversa de personas que trabajan juntas para fortalecer el software.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.4 refleja los innumerables esfuerzos y la pasión <strong>de más de 600 contribuyentes en al menos 56 países</strong>. ¡Este lanzamiento también dio la bienvenida a más de 170 contribuyentes nuevos!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Su colaboración generó más de 1150 mejoras y correcciones, lo que garantizó una versión estable para todos, un testimonio del poder y la capacidad de la comunidad de código abierto de WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://profiles.wordpress.org/6adminit/\">6adminit</a> · <a href=\"https://profiles.wordpress.org/aaroncampbell/\">Aaron D. Campbell</a> · <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a> · <a href=\"https://profiles.wordpress.org/aaronrobertshaw/\">Aaron Robertshaw</a> · <a href=\"https://profiles.wordpress.org/aayusha/\">aayusha</a> · <a href=\"https://profiles.wordpress.org/webcommsat/\">Abha Thakor</a> · <a href=\"https://profiles.wordpress.org/omarabid/\">Abid Omar</a> · <a href=\"https://profiles.wordpress.org/adamsilverstein/\">Adam Silverstein</a> · <a href=\"https://profiles.wordpress.org/adhun/\">Adhun Anand</a> · <a href=\"https://profiles.wordpress.org/ajmcfadyen/\">admcfajn</a> · <a href=\"https://profiles.wordpress.org/adrianduffell/\">adrianduffell</a> · <a href=\"https://profiles.wordpress.org/aegkr/\">aegkr</a> · <a href=\"https://profiles.wordpress.org/ahardyjpl/\">ahardyjpl</a> · <a href=\"https://profiles.wordpress.org/ahmedgeek/\">Ahmed Hussein</a> · <a href=\"https://profiles.wordpress.org/chaion07/\">Ahmed Kabir Chaion</a> · <a href=\"https://profiles.wordpress.org/ajakaroth/\">ajakaroth</a> · <a href=\"https://profiles.wordpress.org/wildworks/\">Aki Hamano</a> · <a href=\"https://profiles.wordpress.org/akihiroharai/\">Akihiro Harai</a> · <a href=\"https://profiles.wordpress.org/atachibana/\">Akira Tachibana</a> · <a href=\"https://profiles.wordpress.org/akshayar/\">Akshaya Rane</a> · <a href=\"https://profiles.wordpress.org/alaminfirdows/\">Al-Amin Firdows</a> · <a href=\"https://profiles.wordpress.org/schlessera/\">Alain Schlesser</a> · <a href=\"https://profiles.wordpress.org/aljullu/\">Albert Juhé Lluveras</a> · <a href=\"https://profiles.wordpress.org/xknown/\">Alex Concha</a> · <a href=\"https://profiles.wordpress.org/alexkingorg/\">Alex King</a> · <a href=\"https://profiles.wordpress.org/ajlende/\">Alex Lende</a> · <